#include <iostream>
#include <algorithm>
using namespace std;

struct Activity {
    int start, end;
};

bool compare(Activity a, Activity b) {
    return a.end < b.end;
}

int main() {
    int n;
    cin >> n;
    Activity activities[100];
    for (int i = 0; i < n; i++) {
        cin >> activities[i].start >> activities[i].end;
    }
    sort(activities, activities + n, compare);
    int count = 1, lastEnd = activities[0].end;
    for (int i = 1; i < n; i++) {
        if (activities[i].start >= lastEnd) {
            count++;
            lastEnd = activities[i].end;
        }
    }
    cout << count << endl;
    return 0;
}
